classdef PaperStudyContract
    %PAPERSTUDYCONTRACT Validated P2 split and held-out access boundary.
    %
    % This class reads only versioned JSON. It does not render or evaluate a
    % case. HELDOUTCASES refuses access until the manifest state is one of the
    % predeclared allowed states. Traceability: algo/main.tex Sec. 10 unified
    % experimental program; implementation plan P2 steps 1--2.

    properties (SetAccess = private)
        StudyFile (1, 1) string
        Identifier (1, 1) string
        State (1, 1) string
        Manifest (1, 1) struct
    end

    methods
        function obj = PaperStudyContract(studyFile)
            arguments
                studyFile (1, 1) string ...
                    {mustBeExistingPaperStudyFile} = ...
                    PaperStudyContract.defaultStudyFile
            end

            s = jsondecode(fileread(studyFile));
            PaperStudyContract.validateManifest(s);
            obj.StudyFile = studyFile;
            obj.Identifier = string(s.identifier);
            obj.State = string(s.state);
            obj.Manifest = s;
        end

        function report = audit(obj)
            %AUDIT Return split/method/governance summary without case rows.
            arguments
                obj (1, 1) PaperStudyContract
            end

            s = obj.Manifest;
            tuning = s.tuningCases;
            heldout = s.heldoutCases;
            report = struct( ...
                "Identifier", obj.Identifier, ...
                "State", obj.State, ...
                "StudyFile", obj.StudyFile, ...
                "TuningCaseCount", numel(tuning), ...
                "HeldoutCaseCount", numel(heldout), ...
                "TuningFactors", ...
                PaperStudyContract.factorSummary(tuning), ...
                "HeldoutFactors", ...
                PaperStudyContract.factorSummary(heldout), ...
                "PrimaryMatchingMethods", ...
                string(s.methods.primaryMatching(:)).', ...
                "DiagnosticMethods", ...
                string(s.methods.diagnosticOnly(:)).', ...
                "DenseMandatoryMethods", ...
                string(s.methods.denseMandatory(:)).', ...
                "MaximumDenseCandidateCount", ...
                s.methods.denseCandidateScreen. ...
                maximumPromotedCandidates, ...
                "HeldoutAccessAllowed", obj.heldoutAccessAllowed, ...
                "OutcomesPresent", isfield(s, "tuningOutcome") ...
                || isfield(s, "heldoutOutcome"), ...
                "Definition", ...
                "manifest audit only; no case rendered or evaluated");
        end

        function cases = tuningCases(obj)
            %TUNINGCASES Return the frozen tuning plan as a table.
            arguments
                obj (1, 1) PaperStudyContract
            end
            cases = PaperStudyContract.caseTable( ...
                obj.Manifest.tuningCases, "tuning");
        end

        function cases = heldoutCases(obj)
            %HELDOUTCASES Return held-out plan only after committed freeze.
            arguments
                obj (1, 1) PaperStudyContract
            end
            if ~obj.heldoutAccessAllowed
                error("PaperStudyContract:HeldoutLocked", ...
                    "Held-out P2 cases remain inaccessible in manifest " ...
                    + "state '%s'. Commit a policy-frozen manifest first.", ...
                    obj.State);
            end
            cases = PaperStudyContract.caseTable( ...
                obj.Manifest.heldoutCases, "heldout");
        end

        function allowed = heldoutAccessAllowed(obj)
            arguments
                obj (1, 1) PaperStudyContract
            end
            allowed = any(string( ...
                obj.Manifest.heldoutAccessAllowedStates) == obj.State);
        end
    end

    methods (Static)
        function path = defaultStudyFile()
            root = fileparts(fileparts(mfilename("fullpath")));
            path = string(fullfile(root, "config", "synthetic", ...
                "paper_study_v1.json"));
        end
    end

    methods (Static, Access = private)
        function validateManifest(s)
            required = ["identifier", "state", ...
                "heldoutAccessAllowedStates", "sceneContract", ...
                "executionParameters", "tunablePolicy", "methods", ...
                "regularization", ...
                "metrics", "statistics", "acceptance", ...
                "tuningCases", "heldoutCases", "governance"];
            if ~isscalar(s) || ~all(isfield(s, required))
                error("PaperStudyContract:InvalidManifest", ...
                    "The P2 manifest is missing required contract fields.");
            end
            states = ["preregistered-unrun", "tuning-complete", ...
                "tuning-invalid", "policy-frozen", "heldout-complete"];
            if ~any(string(s.state) == states)
                error("PaperStudyContract:InvalidState", ...
                    "Unknown P2 manifest state '%s'.", string(s.state));
            end
            PaperStudyContract.validateCases( ...
                s.tuningCases, s.heldoutCases);
            primary = string(s.methods.primaryMatching);
            if numel(primary) ~= numel(unique(primary)) ...
                    || ~all(ismember(["Zncc", "Census", ...
                    "NormalizedGradient", "T0", "T3"], primary))
                error("PaperStudyContract:InvalidMethods", ...
                    "P2 methods must be unique and contain all baselines.");
            end
            map = s.methods.denseCandidateScreen.baselineByCandidate;
            if isempty(map) || ~all(ismember( ...
                    string({map.candidate}), primary)) ...
                    || ~all(ismember(string({map.baseline}), primary))
                error("PaperStudyContract:InvalidMethods", ...
                    "Every dense candidate requires a named primary baseline.");
            end
            if s.sceneContract.targetProjectedMotionPixels <= 0 ...
                    || s.sceneContract.bitDepth ~= 10 ...
                    || ~isfield(s.sceneContract, ...
                    "visibilityWorldToleranceMetres") ...
                    || s.sceneContract.visibilityWorldToleranceMetres <= 0 ...
                    || s.executionParameters.supersample < 1 ...
                    || s.executionParameters.psfSigmaPixels < 0 ...
                    || numel(s.executionParameters.multiHarmonicGates. ...
                    textureNames) ~= numel(s.executionParameters. ...
                    multiHarmonicGates.orthogonalStructureProbability) ...
                    || numel(s.executionParameters.multiHarmonicGates. ...
                    textureNames) ~= numel(s.executionParameters. ...
                    multiHarmonicGates.lowAngularNoiseProbability) ...
                    || s.statistics.bootstrapReplicates < 1 ...
                    || s.methods.denseCandidateScreen. ...
                    maximumPromotedCandidates < 0
                error("PaperStudyContract:InvalidPolicy", ...
                    "P2 numeric policy values are invalid.");
            end
            if ismember(string(s.state), ...
                    ["policy-frozen", "heldout-complete"]) ...
                    && (~isfield(s, "tuningOutcome") ...
                    || ~isfield(s, "frozenPolicy") ...
                    || ~isfield(s, "assessmentPolicy") ...
                    || s.tuningOutcome.heldoutAccessed ...
                    || ~s.tuningOutcome.valid ...
                    || ~s.frozenPolicy.appliedWithoutOverride)
                error("PaperStudyContract:InvalidPolicy", ...
                    "A frozen P2 policy requires tuning-only provenance.");
            end
            if isfield(s, "assessmentPolicy")
                p = s.assessmentPolicy.primaryComparisons;
                if s.assessmentPolicy.primaryFamilySize ~= 4 ...
                        || numel(p) ~= 4 ...
                        || numel(unique(string({p.direction}))) ~= 4 ...
                        || ~all(string({p.stage}) == "RawSparse")
                    error("PaperStudyContract:InvalidPolicy", ...
                        "The frozen assessment requires four raw sparse tests.");
                end
            end
            complete = string(s.state) == "heldout-complete";
            if complete && (~isfield(s, "heldoutOutcome") ...
                    || ~s.heldoutOutcome.heldoutAccessed ...
                    || s.heldoutOutcome.heldoutRunOrdinal ~= 1 ...
                    || ~s.heldoutOutcome.validExecution)
                error("PaperStudyContract:InvalidPolicy", ...
                    "A completed study requires one valid held-out outcome.");
            elseif ~complete && isfield(s, "heldoutOutcome")
                error("PaperStudyContract:InvalidPolicy", ...
                    "A pre-heldout state cannot contain a held-out outcome.");
            end
        end

        function validateCases(tuning, heldout)
            required = ["identifier", "seed", "surface", "texture", ...
                "convergenceDegrees", "obliquityDegrees", ...
                "radiometry", "cameraBias", "lineBiasPixels", ...
                "sampleBiasPixels", "lineDriftPixels", ...
                "sampleDriftPixels"];
            if isempty(tuning) || isempty(heldout) ...
                    || ~all(isfield(tuning, required)) ...
                    || ~all(isfield(heldout, required))
                error("PaperStudyContract:InvalidCases", ...
                    "Both P2 suites require complete, nonempty case rows.");
            end
            ids = [string({tuning.identifier}), ...
                string({heldout.identifier})];
            seeds = [[tuning.seed], [heldout.seed]];
            numeric = [[tuning.convergenceDegrees], ...
                [heldout.convergenceDegrees], ...
                [tuning.obliquityDegrees], ...
                [heldout.obliquityDegrees], seeds];
            if numel(ids) ~= numel(unique(ids)) ...
                    || numel(seeds) ~= numel(unique(seeds)) ...
                    || any(~isfinite(numeric)) ...
                    || any([tuning.convergenceDegrees] <= 0) ...
                    || any([heldout.convergenceDegrees] <= 0)
                error("PaperStudyContract:InvalidCases", ...
                    "P2 identifiers/seeds must be unique and factors valid.");
            end
        end

        function summary = factorSummary(cases)
            summary = struct( ...
                "Surface", PaperStudyContract.countValues( ...
                string({cases.surface})), ...
                "Texture", PaperStudyContract.countValues( ...
                string({cases.texture})), ...
                "ConvergenceDegrees", ...
                PaperStudyContract.countValues( ...
                [cases.convergenceDegrees]), ...
                "ObliquityDegrees", ...
                PaperStudyContract.countValues( ...
                [cases.obliquityDegrees]), ...
                "Radiometry", PaperStudyContract.countValues( ...
                string({cases.radiometry})), ...
                "CameraBias", PaperStudyContract.countValues( ...
                string({cases.cameraBias})));
        end

        function counts = countValues(values)
            [value, ~, group] = unique(values(:), "sorted");
            count = accumarray(group, 1);
            counts = table(value, count, ...
                VariableNames=["Value", "Count"]);
        end

        function t = caseTable(cases, suite)
            n = numel(cases);
            t = table(repmat(suite, n, 1), ...
                string({cases.identifier}).', [cases.seed].', ...
                string({cases.surface}).', string({cases.texture}).', ...
                [cases.convergenceDegrees].', ...
                [cases.obliquityDegrees].', ...
                string({cases.radiometry}).', ...
                string({cases.cameraBias}).', ...
                [cases.lineBiasPixels].', ...
                [cases.sampleBiasPixels].', ...
                [cases.lineDriftPixels].', ...
                [cases.sampleDriftPixels].', ...
                VariableNames=["Suite", "Identifier", "Seed", ...
                "Surface", "Texture", "ConvergenceDegrees", ...
                "ObliquityDegrees", "Radiometry", "CameraBias", ...
                "LineBiasPixels", "SampleBiasPixels", ...
                "LineDriftPixels", "SampleDriftPixels"]);
        end
    end
end

function mustBeExistingPaperStudyFile(path)
if ~isfile(path)
    error("PaperStudyContract:StudyFileNotFound", ...
        "P2 study manifest does not exist: %s", path);
end
end
